/**
 * Sync automatique des scores IRA v1.1 vers des events all-day dans le
 * calendrier "Gr33t Recovery". Appelé en fire-and-forget au démarrage
 * du dashboard, throttlé à 1×/24h.
 *
 * Idempotence : on matche les events existants par **date locale**. Si
 * un event Gr33t all-day existe déjà pour un jour donné → PATCH du
 * subject / body / extension. Sinon → POST.
 *
 * L'utilisateur qui supprime manuellement un event → recréation au
 * prochain run (option "dashboard = source of truth").
 *
 * Extension : `com.gr33t.ira` (schemaVersion 1) — distincte de
 * `com.gr33t.recovery` utilisée par le TaskPane legacy (v1). Cohabitation
 * propre, pas de collision.
 */
import type { DailyScores } from "../dashboard/rythme/scoring/daily";
import { graphFetch, findOrCreateGr33tRecoveryCalendar } from "./graphHttp";
import { buildEventSubject, buildEventBody } from "./scoreEventBody";

export const IRA_EXTENSION_NAME = "com.gr33t.ira";
export const SYNC_LOCALSTORAGE_KEY = "gr33t.lastSync.v1";
const SYNC_THROTTLE_MS = 24 * 60 * 60 * 1000; // 24h

export interface SyncResult {
  /** true si la sync a effectivement tourné (pas throttlée). */
  ran: boolean;
  /** Nb d'events créés (POST). */
  created: number;
  /** Nb d'events mis à jour (PATCH). */
  updated: number;
  /** Nb de jours ignorés (score déjà à jour / erreur par jour). */
  skipped: number;
  /** Erreurs bloquantes globales (ex: 403 scope manquant). */
  error?: string;
}

function pad2(n: number): string {
  return n.toString().padStart(2, "0");
}

function toIsoDate(d: Date): string {
  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}`;
}

function shiftDays(d: Date, days: number): Date {
  const r = new Date(d);
  r.setDate(d.getDate() + days);
  return r;
}

// ─────────────────────────────────────────────────────────────────────
// Throttle
// ─────────────────────────────────────────────────────────────────────

/** true si la dernière sync date de moins de 24h. */
export function isThrottled(
  now: number = Date.now(),
  storage: Storage | undefined = typeof localStorage !== "undefined"
    ? localStorage
    : undefined
): boolean {
  if (!storage) return false;
  const raw = storage.getItem(SYNC_LOCALSTORAGE_KEY);
  if (!raw) return false;
  const last = Date.parse(raw);
  if (Number.isNaN(last)) return false;
  return now - last < SYNC_THROTTLE_MS;
}

function markSynced(now: number = Date.now()): void {
  if (typeof localStorage === "undefined") return;
  try {
    localStorage.setItem(SYNC_LOCALSTORAGE_KEY, new Date(now).toISOString());
  } catch {
    // Quota / privacy mode — on ignore silencieusement
  }
}

// ─────────────────────────────────────────────────────────────────────
// Graph payload helpers
// ─────────────────────────────────────────────────────────────────────

interface ExistingEvent {
  id: string;
  /** ISO "YYYY-MM-DD" extrait de start.dateTime */
  date: string;
}

interface GraphEvent {
  id: string;
  isAllDay?: boolean;
  start?: { dateTime?: string };
}

/** Récupère les events all-day Gr33t dans la fenêtre [start, end]. */
async function fetchExistingEvents(
  token: string,
  calendarId: string,
  startIso: string,
  endIso: string
): Promise<Map<string, ExistingEvent>> {
  const resp = await graphFetch<{ value: GraphEvent[] }>(
    token,
    `/me/calendars/${calendarId}/calendarView` +
      `?startDateTime=${startIso}T00:00:00` +
      `&endDateTime=${endIso}T00:00:00` +
      `&$select=id,isAllDay,start` +
      `&$top=200`
  );
  const out = new Map<string, ExistingEvent>();
  for (const ev of resp.value ?? []) {
    if (!ev.isAllDay) continue;
    const dt = ev.start?.dateTime;
    if (!dt) continue;
    const date = dt.slice(0, 10); // "YYYY-MM-DD"
    // Premier event trouvé pour ce jour gagne (cas rare de doublons)
    if (!out.has(date)) out.set(date, { id: ev.id, date });
  }
  return out;
}

function eventBodyFor(
  isoDate: string,
  scores: DailyScores
): Record<string, unknown> {
  const subject = buildEventSubject(scores);
  const body = buildEventBody(scores);
  const next = new Date(isoDate);
  next.setDate(next.getDate() + 1);
  const nextIso = toIsoDate(next);
  return {
    subject,
    body: { contentType: "html", content: body },
    start: { dateTime: `${isoDate}T00:00:00`, timeZone: "Europe/Paris" },
    end: { dateTime: `${nextIso}T00:00:00`, timeZone: "Europe/Paris" },
    isAllDay: true,
    showAs: "free",
    isReminderOn: false,
  };
}

function extensionPayload(scores: DailyScores, isoDate: string): Record<string, unknown> {
  return {
    "@odata.type": "microsoft.graph.openTypeExtension",
    extensionName: IRA_EXTENSION_NAME,
    schemaVersion: 1,
    source: "dashboard-v1.1",
    date: isoDate,
    scores,
  };
}

// ─────────────────────────────────────────────────────────────────────
// Sync principal
// ─────────────────────────────────────────────────────────────────────

/**
 * Synchronise les scores des 30 derniers jours (J-1 → J-30) vers le
 * calendrier Gr33t Recovery. Throttlé à 1×/24h.
 *
 * @param token Bearer Graph valide
 * @param scoresByDate map ISO→DailyScores (déjà calculée par le dashboard)
 * @param today Date de référence (minuit local). Défaut = maintenant.
 * @param force  Ignore le throttle (tests / bouton debug).
 */
export async function syncScoreEvents(
  token: string,
  scoresByDate: Map<string, DailyScores>,
  today: Date = new Date(),
  force: boolean = false
): Promise<SyncResult> {
  if (!force && isThrottled()) {
    return { ran: false, created: 0, updated: 0, skipped: 0 };
  }

  const result: SyncResult = { ran: true, created: 0, updated: 0, skipped: 0 };

  // Fenêtre : J-30 → J-1 inclus
  const startDate = shiftDays(today, -30);
  const endDate = today; // borne exclusive Graph : J (exclu)
  const startIso = toIsoDate(startDate);
  const endIso = toIsoDate(endDate);

  let calendarId: string;
  let existing: Map<string, ExistingEvent>;
  try {
    calendarId = await findOrCreateGr33tRecoveryCalendar(token);
    existing = await fetchExistingEvents(token, calendarId, startIso, endIso);
  } catch (err) {
    const e = err as { status?: number; message?: string };
    if (e.status === 401) {
      return { ...result, ran: false, error: "auth" };
    }
    if (e.status === 403) {
      result.error = "Scope Calendars.ReadWrite requis (relogin nécessaire).";
      return result;
    }
    result.error = e.message ?? String(err);
    return result;
  }

  // Parcourt J-30 → J-1 (30 jours) et upsert chaque jour avec un score
  for (let offset = 1; offset <= 30; offset++) {
    const day = shiftDays(today, -offset);
    const iso = toIsoDate(day);
    const scores = scoresByDate.get(iso);
    if (!scores) {
      result.skipped++;
      continue;
    }

    const existingEv = existing.get(iso);
    const payload = eventBodyFor(iso, scores);
    const ext = extensionPayload(scores, iso);

    try {
      if (existingEv) {
        // PATCH existant + PATCH/POST de l'extension
        await graphFetch(token, `/me/events/${existingEv.id}`, {
          method: "PATCH",
          body: JSON.stringify(payload),
        });
        await upsertExtension(token, existingEv.id, ext);
        result.updated++;
      } else {
        // POST avec extension embarquée
        await graphFetch(token, `/me/calendars/${calendarId}/events`, {
          method: "POST",
          body: JSON.stringify({ ...payload, extensions: [ext] }),
        });
        result.created++;
      }
    } catch {
      // Erreur isolée sur 1 jour → on continue
      result.skipped++;
    }
  }

  // Ne marque "synced" que si au moins 1 écriture réussie, sinon on
  // retentera au prochain open (évite de coincer à cause d'une panne).
  if (result.created + result.updated > 0) {
    markSynced();
  }
  return result;
}

async function upsertExtension(
  token: string,
  eventId: string,
  ext: Record<string, unknown>
): Promise<void> {
  try {
    await graphFetch(
      token,
      `/me/events/${eventId}/extensions/${IRA_EXTENSION_NAME}`,
      { method: "PATCH", body: JSON.stringify(ext) }
    );
  } catch (err) {
    const e = err as { status?: number };
    if (e.status === 404) {
      // Extension absente → POST
      await graphFetch(token, `/me/events/${eventId}/extensions`, {
        method: "POST",
        body: JSON.stringify(ext),
      });
      return;
    }
    throw err;
  }
}
