/**
 * Moteur de détection automatique des annotations affichées sur la timeline.
 *
 * Règles (chat 19 avril) :
 *   Passé :
 *     - Période : S-1 (lun-ven) + lun..J-1 de S (exclut aujourd'hui)
 *     - Un jour est candidat si ≥ 1 facteur a un score < 50%
 *     - Pour un jour candidat : on annote le PIRE facteur
 *     - Max 3 annotations passées, choisies par gravité = 100 - worstFactor
 *   Futur :
 *     - Période : aujourd'hui → fin de S+1 (vendredi)
 *     - Pattern "subies" : ≥ 1 réunion où user est invité + pas `transBefore` min libres avant
 *     - Pattern "jointives" : ≥ 2 réunions enchaînées (0 min entre) où user est organizer
 *     - Si les 2 patterns sur un même jour → "jointives" prévaut (plus actionnable)
 *     - Max 2 annotations futures, choisies par gravité = nb réunions à risque
 *   Numérotation : chronologique (du plus ancien au plus récent), 1..N
 *   shownByDefault : 1 passée la plus grave + 1 future la plus grave
 *
 * Tous les seuils temporels (plage de travail, transition) viennent de la
 * `QvctPolicy` (cf. src/dashboard/rythme/config/policy.ts).
 */
import type { Annotation } from "../types/data-contract";
import type { DailyScores } from "../scoring/daily";
import { CONSEILS, type AnnotationKind } from "./templates";
import {
  DEFAULT_POLICY,
  workStartMin,
  workEndMin,
  transBeforeMs,
  transAfterMs,
  type QvctPolicy,
} from "../config/policy";

// ============================================================
// Types d'entrée
// ============================================================

export interface DetectMeeting {
  start: Date;
  end: Date;
  isOrganizer: boolean;
  otherAttendees: number;
  /** Titre de la réunion — utilisé dans la description des bulles. */
  subject: string;
}

export interface DetectSend {
  sentAt: Date;
}

export interface DetectInputs {
  /** `today` à minuit local (on ignore l'heure). */
  today: Date;
  /** Lundi de la semaine passée (S-1) — format ISO "YYYY-MM-DD". */
  mondayPast: string;
  /** Lundi de la semaine courante (S). */
  mondayCurrent: string;
  /** Lundi de la semaine suivante (S+1). */
  mondayNext: string;
  /** Scores journaliers par date ISO. */
  scoresByDate: Map<string, DailyScores>;
  /** Réunions indexées par date ISO "YYYY-MM-DD" (jour local). */
  meetingsByDate: Map<string, DetectMeeting[]>;
  /** Envois mail indexés par date ISO. Requis pour chiffrer les descriptions. */
  sendsByDate: Map<string, DetectSend[]>;
  /** Politique QVCT. Défaut = `DEFAULT_POLICY`. */
  policy?: QvctPolicy;
}

// ============================================================
// Helpers dates
// ============================================================
function pad2(n: number): string {
  return n.toString().padStart(2, "0");
}
function toIso(d: Date): string {
  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}`;
}
function parseIso(iso: string): Date {
  const [y, m, d] = iso.split("-").map(Number);
  return new Date(y, m - 1, d);
}
function shiftDays(d: Date, days: number): Date {
  const r = new Date(d);
  r.setDate(d.getDate() + days);
  return r;
}
function isWeekend(d: Date): boolean {
  const day = d.getDay();
  return day === 0 || day === 6;
}

const WEEKDAY_SHORT = ["Dim", "Lun", "Mar", "Mer", "Jeu", "Ven", "Sam"];
const MONTHS_SHORT = [
  "janv.",
  "févr.",
  "mars",
  "avril",
  "mai",
  "juin",
  "juil.",
  "août",
  "sept.",
  "oct.",
  "nov.",
  "déc.",
];

/** Formatage humain d'une heure "h:mm" → "8h" ou "18h30". */
function formatHour(h: number, m: number): string {
  return m === 0 ? `${h}h` : `${h}h${pad2(m)}`;
}

// ============================================================
// Layout horizontal de la bulle (pct de la timeline wrap)
// Grille : weeks 1fr 1.2fr 1fr = total 3.2 (sans gaps)
// ============================================================
const WEEK_WIDTHS = [1, 1.2, 1];
const WEEK_TOTAL = WEEK_WIDTHS.reduce((a, b) => a + b, 0);

function computeBubbleLeftPct(
  targetDate: string,
  mondayPast: string,
  mondayCurrent: string,
  mondayNext: string
): number {
  const mondays = [mondayPast, mondayCurrent, mondayNext];
  for (let w = 0; w < 3; w++) {
    for (let i = 0; i < 5; i++) {
      const d = shiftDays(parseIso(mondays[w]), i);
      if (toIso(d) === targetDate) {
        // Position de début de la semaine (en %)
        let weekStart = 0;
        for (let k = 0; k < w; k++) {
          weekStart += (WEEK_WIDTHS[k] / WEEK_TOTAL) * 100;
        }
        const weekWidth = (WEEK_WIDTHS[w] / WEEK_TOTAL) * 100;
        // Centre du jour i (sur 5 jours uniformément)
        return weekStart + ((i + 0.5) / 5) * weekWidth;
      }
    }
  }
  return 50; // fallback (ne devrait pas arriver)
}

// ============================================================
// Formatage titre de bulle
// ============================================================
function formatDayShort(date: Date): string {
  return `${WEEKDAY_SHORT[date.getDay()]} ${date.getDate()} ${
    MONTHS_SHORT[date.getMonth()]
  }`;
}

// ============================================================
// PASSÉ — détection des jours faibles
// ============================================================

type FactorKey = "transitions" | "concentration" | "horaires" | "focus";

const FACTOR_TO_KIND: Record<FactorKey, AnnotationKind> = {
  transitions: "past-transitions",
  concentration: "past-concentration",
  horaires: "past-horaires",
  focus: "past-focus",
};

/** Titre court (uppercased) affiché dans la bulle. */
const FACTOR_TITLE: Record<FactorKey, string> = {
  transitions: "réunions enchaînées",
  concentration: "journée fragmentée",
  horaires: "débordement horaire",
  focus: "multitâche en réunion",
};

const FOCUS_MIN_MS = 2 * 60 * 60 * 1000;

function minutesOfDay(d: Date): number {
  return d.getHours() * 60 + d.getMinutes();
}

/** Description chiffrée pour Transitions : "X réunions sur Y sans…". */
function describeTransitions(
  meetings: DetectMeeting[],
  sends: DetectSend[],
  policy: QvctPolicy
): string {
  if (meetings.length === 0) return "Aucune réunion ce jour-là.";
  const tBefore = transBeforeMs(policy);
  const tAfter = transAfterMs(policy);
  const sorted = [...meetings].sort(
    (a, b) => a.start.getTime() - b.start.getTime()
  );
  let ko = 0;
  sorted.forEach((m, i) => {
    const isFirst = i === 0;
    const isLast = i === sorted.length - 1;
    const winBefore = new Date(m.start.getTime() - tBefore);
    const winAfter = new Date(m.end.getTime() + tAfter);
    const beforeOk =
      isFirst ||
      tBefore === 0 ||
      (!sorted.some(
        (o) => o !== m && o.start < m.start && o.end > winBefore
      ) &&
        !sends.some((s) => s.sentAt >= winBefore && s.sentAt < m.start));
    const afterOk =
      isLast ||
      tAfter === 0 ||
      (!sorted.some((o) => o !== m && o.end > m.end && o.start < winAfter) &&
        !sends.some((s) => s.sentAt > m.end && s.sentAt <= winAfter));
    if (!beforeOk && !afterOk) ko++;
  });
  const total = meetings.length;
  const tMin = Math.max(policy.transBeforeMin, policy.transAfterMin);
  return `${ko} réunion${ko > 1 ? "s" : ""} sur ${total} sans ${tMin} min libres avant ou après.`;
}

/** Description chiffrée pour Concentration : nb de plages ≥ 2h dans la fenêtre. */
function describeConcentration(
  meetings: DetectMeeting[],
  sends: DetectSend[],
  policy: QvctPolicy
): string {
  if (meetings.length === 0 && sends.length === 0) {
    return "Journée sans activité numérique détectée.";
  }
  const allTimes: Date[] = [
    ...meetings.flatMap((m) => [m.start, m.end]),
    ...sends.map((s) => s.sentAt),
  ];
  const first = new Date(Math.min(...allTimes.map((t) => t.getTime())));
  const last = new Date(Math.max(...allTimes.map((t) => t.getTime())));
  const day0 = new Date(first);
  day0.setHours(policy.workStart.h, policy.workStart.m, 0, 0);
  const day1 = new Date(first);
  day1.setHours(policy.workEnd.h, policy.workEnd.m, 0, 0);
  const start = first > day0 ? first : day0;
  const end = last < day1 ? last : day1;
  const cuts: number[] = [start.getTime()];
  for (const m of meetings) {
    if (m.start >= start && m.start <= end) cuts.push(m.start.getTime());
    if (m.end >= start && m.end <= end) cuts.push(m.end.getTime());
  }
  for (const s of sends) {
    if (s.sentAt >= start && s.sentAt <= end) cuts.push(s.sentAt.getTime());
  }
  cuts.push(end.getTime());
  cuts.sort((a, b) => a - b);
  let plages = 0;
  for (let i = 0; i < cuts.length - 1; i++) {
    const seg = cuts[i + 1] - cuts[i];
    const mid = (cuts[i] + cuts[i + 1]) / 2;
    const insideMeeting = meetings.some(
      (m) => m.start.getTime() <= mid && m.end.getTime() > mid
    );
    if (insideMeeting) continue;
    if (seg >= FOCUS_MIN_MS) plages++;
  }
  if (plages === 0) return "Aucune plage de 2h sans interruption ce jour-là.";
  return `Seulement ${plages} plage${plages > 1 ? "s" : ""} de 2h sans interruption.`;
}

/** Description chiffrée pour Horaires : type précis du débordement. */
function describeHoraires(
  meetings: DetectMeeting[],
  sends: DetectSend[],
  policy: QvctPolicy
): string {
  const wStart = workStartMin(policy);
  const wEnd = workEndMin(policy);
  const startLabel = formatHour(policy.workStart.h, policy.workStart.m);
  const endLabel = formatHour(policy.workEnd.h, policy.workEnd.m);

  const parts: string[] = [];
  const earlyMails = sends.filter((s) => minutesOfDay(s.sentAt) < wStart).length;
  const lateMails = sends.filter((s) => minutesOfDay(s.sentAt) > wEnd).length;
  const earlyMtgs = meetings.filter((m) => minutesOfDay(m.start) < wStart).length;
  const lateMtgs = meetings.filter((m) => minutesOfDay(m.end) > wEnd).length;

  if (earlyMails) parts.push(`${earlyMails} mail${earlyMails > 1 ? "s" : ""} envoyé${earlyMails > 1 ? "s" : ""} avant ${startLabel}`);
  if (lateMails) parts.push(`${lateMails} mail${lateMails > 1 ? "s" : ""} envoyé${lateMails > 1 ? "s" : ""} après ${endLabel}`);
  if (earlyMtgs) parts.push(`${earlyMtgs} réunion${earlyMtgs > 1 ? "s" : ""} avant ${startLabel}`);
  if (lateMtgs) parts.push(`${lateMtgs} réunion${lateMtgs > 1 ? "s" : ""} après ${endLabel}`);

  if (parts.length === 0) {
    return `Activité professionnelle hors plage ${startLabel}-${endLabel}.`;
  }
  if (parts.length === 1) return parts[0] + ".";
  const last = parts[parts.length - 1];
  return parts.slice(0, -1).join(", ") + " et " + last + ".";
}

/** Description chiffrée pour Focus : nb de réunions interrompues. */
function describeFocus(
  meetings: DetectMeeting[],
  sends: DetectSend[]
): string {
  const real = meetings.filter((m) => m.otherAttendees >= 1);
  if (real.length === 0) return "Aucune réunion avec des participants ce jour-là.";
  const ko = real.filter((m) =>
    sends.some((s) => s.sentAt >= m.start && s.sentAt <= m.end)
  ).length;
  if (ko === 0) {
    return "Pas de mail envoyé pendant les réunions.";
  }
  return `${ko} réunion${ko > 1 ? "s" : ""} sur ${real.length} interrompue${
    ko > 1 ? "s" : ""
  } par un envoi de mail.`;
}

function describeFactor(
  factor: FactorKey,
  meetings: DetectMeeting[],
  sends: DetectSend[],
  policy: QvctPolicy
): string {
  switch (factor) {
    case "transitions":
      return describeTransitions(meetings, sends, policy);
    case "concentration":
      return describeConcentration(meetings, sends, policy);
    case "horaires":
      return describeHoraires(meetings, sends, policy);
    case "focus":
      return describeFocus(meetings, sends);
  }
}

interface PastCandidate {
  date: string;           // ISO
  dayDate: Date;
  worstFactor: FactorKey;
  worstValue: number;     // 0-100 (plus c'est bas, plus c'est grave)
  meetings: DetectMeeting[];
  sends: DetectSend[];
}

function collectPastCandidates(input: DetectInputs): PastCandidate[] {
  const candidates: PastCandidate[] = [];
  const yesterday = shiftDays(input.today, -1);
  let cursor = parseIso(input.mondayPast);
  while (cursor <= yesterday) {
    const iso = toIso(cursor);
    if (!isWeekend(cursor)) {
      const s = input.scoresByDate.get(iso);
      if (s) {
        const factors: Array<[FactorKey, number]> = [
          ["transitions", s.transitions],
          ["concentration", s.concentration],
          ["horaires", s.horaires],
          ["focus", s.focus],
        ];
        const [worstFactor, worstValue] = factors.reduce((a, b) =>
          a[1] <= b[1] ? a : b
        );
        if (worstValue < 50) {
          candidates.push({
            date: iso,
            dayDate: new Date(cursor),
            worstFactor,
            worstValue,
            meetings: input.meetingsByDate.get(iso) ?? [],
            sends: input.sendsByDate.get(iso) ?? [],
          });
        }
      }
    }
    cursor = shiftDays(cursor, 1);
  }
  candidates.sort((a, b) => a.worstValue - b.worstValue);
  return candidates.slice(0, 3);
}

function buildPastBubble(
  c: PastCandidate,
  policy: QvctPolicy
): { title: string; description: string } {
  return {
    title: `${formatDayShort(c.dayDate)} · ${FACTOR_TITLE[c.worstFactor]}`,
    description: describeFactor(c.worstFactor, c.meetings, c.sends, policy),
  };
}

function pastMarkerColor(value: number): Annotation["markerColor"] {
  return value < 30 ? "red" : "orange";
}

// ============================================================
// FUTUR — détection
// ============================================================

interface FutureCandidate {
  date: string;
  dayDate: Date;
  pattern: "backtoback" | "jointives";
  count: number;
  windowSummary: string;
  subjects: string[];
}

function formatHourRange(meetings: DetectMeeting[]): string {
  if (meetings.length === 0) return "";
  const sorted = [...meetings].sort((a, b) => a.start.getTime() - b.start.getTime());
  const start = sorted[0].start;
  const end = sorted[sorted.length - 1].end;
  const fmt = (d: Date) => formatHour(d.getHours(), d.getMinutes());
  return `${fmt(start)}-${fmt(end)}`;
}

function detectFutureDay(
  iso: string,
  dayDate: Date,
  meetings: DetectMeeting[],
  policy: QvctPolicy
): FutureCandidate | null {
  if (meetings.length === 0) return null;
  const sorted = [...meetings].sort((a, b) => a.start.getTime() - b.start.getTime());

  // Pattern B d'abord (prévaut) : réunions jointives organisées
  const jointivesOrganisees: DetectMeeting[] = [];
  for (let i = 0; i < sorted.length - 1; i++) {
    const a = sorted[i];
    const b = sorted[i + 1];
    if (!a.isOrganizer || !b.isOrganizer) continue;
    const gap = b.start.getTime() - a.end.getTime();
    if (gap < 60 * 1000) {
      jointivesOrganisees.push(a, b);
    }
  }
  if (jointivesOrganisees.length > 0) {
    const uniq = Array.from(new Set(jointivesOrganisees)).sort(
      (a, b) => a.start.getTime() - b.start.getTime()
    );
    return {
      date: iso,
      dayDate,
      pattern: "jointives",
      count: uniq.length,
      windowSummary: formatHourRange(uniq),
      subjects: uniq.map((m) => m.subject),
    };
  }

  // Pattern A : réunions subies sans transition avant
  const tBefore = transBeforeMs(policy);
  const subies: DetectMeeting[] = [];
  sorted.forEach((m, idx) => {
    if (m.isOrganizer) return;
    if (idx === 0) return;
    const prev = sorted[idx - 1];
    const gap = m.start.getTime() - prev.end.getTime();
    if (gap < tBefore) subies.push(m);
  });
  if (subies.length > 0) {
    return {
      date: iso,
      dayDate,
      pattern: "backtoback",
      count: subies.length,
      windowSummary: formatHourRange(subies),
      subjects: subies.map((m) => m.subject),
    };
  }

  return null;
}

function collectFutureCandidates(input: DetectInputs, policy: QvctPolicy): FutureCandidate[] {
  const out: FutureCandidate[] = [];
  const end = shiftDays(parseIso(input.mondayNext), 4);
  let cursor = new Date(input.today);
  while (cursor <= end) {
    if (!isWeekend(cursor)) {
      const iso = toIso(cursor);
      const meetings = input.meetingsByDate.get(iso) ?? [];
      const detected = detectFutureDay(iso, new Date(cursor), meetings, policy);
      if (detected) out.push(detected);
    }
    cursor = shiftDays(cursor, 1);
  }
  out.sort((a, b) => b.count - a.count);
  return out.slice(0, 2);
}

function joinSubjects(subjects: string[]): string {
  const quoted = subjects.map((s) => `« ${s} »`);
  if (quoted.length <= 1) return quoted.join("");
  if (quoted.length === 2) return `${quoted[0]} et ${quoted[1]}`;
  const last = quoted[quoted.length - 1];
  return `${quoted.slice(0, -1).join(", ")} et ${last}`;
}

function buildFutureBubble(
  c: FutureCandidate
): { title: string; description: string } {
  if (c.pattern === "jointives") {
    return {
      title: `${formatDayShort(c.dayDate)} · ${c.count} réunions enchaînées`,
      description: `Vous organisez ${c.count} réunions qui s'enchaînent sans transition : ${joinSubjects(
        c.subjects
      )}.`,
    };
  }
  return {
    title: `${formatDayShort(c.dayDate)} · ${c.count} réunion${
      c.count > 1 ? "s" : ""
    } ${c.windowSummary}`,
    description: `Réunion${c.count > 1 ? "s" : ""} invitée${
      c.count > 1 ? "s" : ""
    } sans temps de récupération avant : ${joinSubjects(c.subjects)}.`,
  };
}

// ============================================================
// Assemblage final
// ============================================================

export function detectAnnotations(input: DetectInputs): Annotation[] {
  const policy = input.policy ?? DEFAULT_POLICY;
  const past = collectPastCandidates(input);
  const future = collectFutureCandidates(input, policy);

  const topPastId =
    past.length > 0
      ? `annot-${past[0].date}-${FACTOR_TO_KIND[past[0].worstFactor]}`
      : null;
  const topFutureId =
    future.length > 0
      ? `annot-${future[0].date}-future-${future[0].pattern}`
      : null;

  type Raw = Omit<Annotation, "number" | "shownByDefault">;
  const raw: Raw[] = [];

  for (const p of past) {
    const kind = FACTOR_TO_KIND[p.worstFactor];
    const id = `annot-${p.date}-${kind}`;
    const { title, description } = buildPastBubble(p, policy);
    raw.push({
      id,
      temporality: "past",
      markerColor: pastMarkerColor(p.worstValue),
      targetDate: p.date,
      bubbleLeftPct: computeBubbleLeftPct(
        p.date,
        input.mondayPast,
        input.mondayCurrent,
        input.mondayNext
      ),
      bubble: { title, description },
      conseil: CONSEILS[kind],
    });
  }

  for (const f of future) {
    const kind: AnnotationKind = `future-${
      f.pattern === "jointives" ? "jointives" : "backtoback"
    }` as AnnotationKind;
    const id = `annot-${f.date}-future-${f.pattern}`;
    const { title, description } = buildFutureBubble(f);
    raw.push({
      id,
      temporality: "future",
      markerColor: "orange",
      targetDate: f.date,
      bubbleLeftPct: computeBubbleLeftPct(
        f.date,
        input.mondayPast,
        input.mondayCurrent,
        input.mondayNext
      ),
      bubble: { title, description },
      conseil: CONSEILS[kind],
    });
  }

  raw.sort((a, b) => a.targetDate.localeCompare(b.targetDate));
  const annotations: Annotation[] = raw.map((r, idx) => ({
    ...r,
    number: idx + 1,
    shownByDefault: r.id === topPastId || r.id === topFutureId,
  }));

  return annotations;
}

// Exposé pour tests
export const _internal = {
  computeBubbleLeftPct,
  collectPastCandidates,
  collectFutureCandidates,
  pastMarkerColor,
  FACTOR_TO_KIND,
};
