import * as React from "react";
import styles from "./PolicyPanel.module.css";
import {
  DEFAULT_POLICY,
  clonePolicy,
  policiesEqual,
  validatePolicy,
  type QvctPolicy,
  type IraWeights,
} from "../../config/policy";
import { usePolicy } from "../../config/PolicyProvider";

// ────────────────────────────────────────────────────────────────────────────
// Inputs atomiques
// ────────────────────────────────────────────────────────────────────────────

interface TimeInputProps {
  label: string;
  value: { h: number; m: number };
  onChange: (v: { h: number; m: number }) => void;
  error?: string;
}

const TimeInput: React.FC<TimeInputProps> = ({ label, value, onChange, error }) => {
  const hh = (e: React.ChangeEvent<HTMLInputElement>) => {
    const n = parseInt(e.target.value, 10);
    onChange({ ...value, h: Number.isFinite(n) ? n : 0 });
  };
  const mm = (e: React.ChangeEvent<HTMLInputElement>) => {
    const n = parseInt(e.target.value, 10);
    onChange({ ...value, m: Number.isFinite(n) ? n : 0 });
  };
  return (
    <div className={`${styles.field} ${error ? styles.fieldErrorWrap : ""}`}>
      <span className={styles.label}>{label}</span>
      <div className={styles.timeInput}>
        <input
          type="number"
          min={0}
          max={23}
          value={String(value.h).padStart(2, "0")}
          onChange={hh}
          aria-label={`${label} — heures`}
        />
        <span className={styles.timeSeparator}>:</span>
        <input
          type="number"
          min={0}
          max={59}
          value={String(value.m).padStart(2, "0")}
          onChange={mm}
          aria-label={`${label} — minutes`}
        />
      </div>
      <div className={styles.fieldError}>{error ?? ""}</div>
    </div>
  );
};

interface MinutesInputProps {
  label: string;
  value: number;
  onChange: (v: number) => void;
  error?: string;
  bounds?: string;
}

const MinutesInput: React.FC<MinutesInputProps> = ({
  label,
  value,
  onChange,
  error,
  bounds,
}) => {
  return (
    <div className={`${styles.field} ${error ? styles.fieldErrorWrap : ""}`}>
      <span className={styles.label}>{label}</span>
      <div className={styles.numberInput}>
        <input
          type="number"
          min={0}
          max={60}
          value={value}
          onChange={(e) => {
            const n = parseInt(e.target.value, 10);
            onChange(Number.isFinite(n) ? n : 0);
          }}
          aria-label={label}
        />
        <span className={styles.unit}>min</span>
      </div>
      {bounds && <span className={styles.boundsHint}>{bounds}</span>}
      <div className={styles.fieldError}>{error ?? ""}</div>
    </div>
  );
};

interface WeightRowProps {
  label: string;
  value: number; // en fraction 0..1
  onChange: (pct: number) => void; // pct entier
}

const WeightRow: React.FC<WeightRowProps> = ({ label, value, onChange }) => {
  const pct = Math.round(value * 100);
  return (
    <>
      <span className={styles.weightLabel}>{label}</span>
      <div className={styles.numberInput}>
        <input
          type="number"
          min={0}
          max={100}
          value={pct}
          onChange={(e) => {
            const n = parseInt(e.target.value, 10);
            onChange(Number.isFinite(n) ? Math.max(0, Math.min(100, n)) : 0);
          }}
          aria-label={`${label} — pourcentage`}
        />
        <span className={styles.unit}>%</span>
      </div>
      <div className={styles.weightBar}>
        <div className={styles.weightBarFill} style={{ width: `${pct}%` }} />
      </div>
    </>
  );
};

// ────────────────────────────────────────────────────────────────────────────
// PolicyPanel
// ────────────────────────────────────────────────────────────────────────────

export const PolicyPanel: React.FC = () => {
  const { policy, save, saveStatus, saveError, loadStatus } = usePolicy();

  // Draft local (indépendant du store tant que pas sauvegardé)
  const [draft, setDraft] = React.useState<QvctPolicy>(() => clonePolicy(policy));

  // Resynchronise le draft si la policy store change (ex: reload Graph)
  React.useEffect(() => {
    setDraft(clonePolicy(policy));
  }, [policy]);

  const validation = validatePolicy(draft);
  const isDirty = !policiesEqual(draft, policy);
  const canSave =
    validation.ok && isDirty && saveStatus !== "saving" && loadStatus !== "loading";

  const onReset = () => setDraft(clonePolicy(DEFAULT_POLICY));

  const onSave = async () => {
    try {
      await save(draft);
    } catch {
      // L'erreur est déjà exposée via saveError
    }
  };

  const setWorkStart = (v: { h: number; m: number }) =>
    setDraft((d) => ({ ...d, workStart: v }));
  const setWorkEnd = (v: { h: number; m: number }) =>
    setDraft((d) => ({ ...d, workEnd: v }));
  const setTransBefore = (v: number) =>
    setDraft((d) => ({ ...d, transBeforeMin: v }));
  const setTransAfter = (v: number) =>
    setDraft((d) => ({ ...d, transAfterMin: v }));
  const setWeight = (k: keyof IraWeights) => (pct: number) =>
    setDraft((d) => ({
      ...d,
      weights: { ...d.weights, [k]: pct / 100 },
    }));

  const weightsSumPct = Math.round(
    (draft.weights.transitions +
      draft.weights.concentration +
      draft.weights.horaires +
      draft.weights.focus) *
      100
  );
  const weightsOk = weightsSumPct === 100;

  // Erreur de plage (workStart >= workEnd) affichée sous workEnd
  const workRangeErr = validation.errors.workRange;

  return (
    <div className={styles.wrap}>
      <header className={styles.header}>
        <div className={styles.title}>
          Politique QVCT — paramètres du calcul IRA
        </div>
      </header>

      {saveStatus === "saved" && (
        <div className={`${styles.banner} ${styles.bannerSuccess}`}>
          <span className="material-symbols-rounded" aria-hidden>
            check_circle
          </span>
          Politique enregistrée. Les scores seront recalculés au prochain
          rafraîchissement.
        </div>
      )}
      {saveStatus === "error" && saveError && (
        <div className={`${styles.banner} ${styles.bannerError}`}>
          <span className="material-symbols-rounded" aria-hidden>
            error
          </span>
          {saveError}
        </div>
      )}

      <div className={styles.card}>
        <div className={styles.grid}>
          <div className={styles.colLeft}>
        {/* === Horaires === */}
        <div className={styles.section}>
          <div className={styles.sectionTitle}>
            <span className="material-symbols-rounded" aria-hidden>
              schedule
            </span>
            Horaires de travail
          </div>
          <div className={styles.sectionHelp}>
            Plage de référence utilisée pour le facteur <strong>Horaires</strong>
            , pour délimiter les plages de <strong>Concentration</strong>, et pour
            détecter les mails/réunions hors plage.
          </div>
          <div className={styles.fieldRow}>
            <TimeInput
              label="Début"
              value={draft.workStart}
              onChange={setWorkStart}
              error={validation.errors.workStart}
            />
            <span className={styles.rangeSeparator}>→</span>
            <TimeInput
              label="Fin"
              value={draft.workEnd}
              onChange={setWorkEnd}
              error={validation.errors.workEnd ?? workRangeErr}
            />
          </div>
        </div>

        {/* === Transitions === */}
        <div className={styles.section}>
          <div className={styles.sectionTitle}>
            <span className="material-symbols-rounded" aria-hidden>
              pace
            </span>
            Transitions autour des réunions
          </div>
          <div className={styles.sectionHelp}>
            Durée minimale de pause <strong>avant</strong> et{" "}
            <strong>après</strong> une réunion pour qu'elle soit considérée comme
            correctement encadrée (facteur <strong>Transitions</strong>).
          </div>
          <div className={styles.fieldRow}>
            <MinutesInput
              label="Avant"
              value={draft.transBeforeMin}
              onChange={setTransBefore}
              error={validation.errors.transBeforeMin}
              bounds="0 à 60 min"
            />
            <MinutesInput
              label="Après"
              value={draft.transAfterMin}
              onChange={setTransAfter}
              error={validation.errors.transAfterMin}
              bounds="0 à 60 min"
            />
          </div>
        </div>
          </div>

          <div className={styles.colRight}>
        {/* === Pondérations IRA === */}
        <div className={styles.section}>
          <div className={styles.sectionTitle}>
            <span className="material-symbols-rounded" aria-hidden>
              tune
            </span>
            Pondérations IRA
          </div>
          <div className={styles.sectionHelp}>
            Poids des 4 facteurs dans le calcul de l'IRA (somme = 100 %, valeurs
            entières).
          </div>
          <div className={styles.weightGrid}>
            <WeightRow
              label="Transitions"
              value={draft.weights.transitions}
              onChange={setWeight("transitions")}
            />
            <WeightRow
              label="Concentration"
              value={draft.weights.concentration}
              onChange={setWeight("concentration")}
            />
            <WeightRow
              label="Horaires"
              value={draft.weights.horaires}
              onChange={setWeight("horaires")}
            />
            <WeightRow
              label="Focus en réunion"
              value={draft.weights.focus}
              onChange={setWeight("focus")}
            />
          </div>
          <div className={styles.weightTotal}>
            <span>Total</span>
            <span
              className={weightsOk ? styles.weightTotalOk : styles.weightTotalKo}
            >
              {weightsSumPct} %
              {weightsOk ? " ✓" : " — doit être 100 %"}
            </span>
          </div>
        </div>
          </div>
        </div>

        {/* === Actions === */}
        <div className={styles.actions}>
          <button
            type="button"
            className={styles.reset}
            onClick={onReset}
            disabled={saveStatus === "saving"}
          >
            Rétablir les valeurs par défaut
          </button>
          <button
            type="button"
            className={styles.save}
            onClick={() => void onSave()}
            disabled={!canSave}
            aria-disabled={!canSave}
          >
            <span className="material-symbols-rounded" aria-hidden>
              {saveStatus === "saving" ? "sync" : "save"}
            </span>
            {saveStatus === "saving" ? "Enregistrement…" : "Enregistrer"}
          </button>
        </div>
      </div>
    </div>
  );
};
