/**
 * Persistance de la politique QVCT via Microsoft Graph.
 *
 * Format de stockage :
 *   - Calendrier : "Gr33t Recovery" (créé si absent)
 *   - Événement all-day dédié "Gr33t Policy" au 1970-01-01 (sentinelle)
 *   - Extension openTypeExtension "com.gr33t.policy" portant la politique JSON
 *
 * Cette stratégie :
 *   - ne pollue pas l'agenda visible (1970-01-01 hors champ des 30 derniers jours)
 *   - tire parti de la même infrastructure que les scores quotidiens
 *   - permet de lire/écrire sans introduire de nouveau stockage
 *
 * API :
 *   - `readPolicyFromGraph(token)` → `QvctPolicy | null` (null si absent ou erreur)
 *   - `writePolicyToGraph(token, policy)` → void (upsert)
 */
import {
  DEFAULT_POLICY,
  clonePolicy,
  validatePolicy,
  type QvctPolicy,
} from "../dashboard/rythme/config/policy";
import {
  graphFetch,
  findOrCreateGr33tRecoveryCalendar,
} from "./graphHttp";

const POLICY_EVENT_SUBJECT = "Gr33t Policy";
const POLICY_EXTENSION_NAME = "com.gr33t.policy";
const POLICY_SENTINEL_START = "1970-01-01";
const POLICY_SENTINEL_END = "1970-01-02";

interface PolicyEvent {
  id: string;
}

/** Trouve l'événement sentinelle (1970-01-01) ou renvoie null. */
async function findPolicyEvent(
  token: string,
  calendarId: string
): Promise<PolicyEvent | null> {
  // On ne peut pas filtrer par subject + date all-day facilement ; on liste
  // les events du calendrier "Gr33t Recovery" et on retient celui qui
  // correspond au sujet réservé. Le calendrier ne contient que des events
  // Gr33t, le coût est faible.
  const resp = await graphFetch<{ value: { id: string; subject?: string; start: { dateTime: string } }[] }>(
    token,
    `/me/calendars/${calendarId}/events?$select=id,subject,start&$top=200`
  );
  return (
    resp.value?.find(
      (ev) =>
        ev.subject === POLICY_EVENT_SUBJECT &&
        typeof ev.start?.dateTime === "string" &&
        ev.start.dateTime.startsWith(POLICY_SENTINEL_START)
    ) ?? null
  );
}

/**
 * Lit la politique QVCT depuis Graph.
 * Retourne null si non trouvée ou si la valeur stockée est invalide.
 * Toute erreur réseau est remontée à l'appelant.
 */
export async function readPolicyFromGraph(
  token: string
): Promise<QvctPolicy | null> {
  const calendarId = await findOrCreateGr33tRecoveryCalendar(token);
  const ev = await findPolicyEvent(token, calendarId);
  if (!ev) return null;

  interface ExtResp { value: { extensionName?: string; payload?: string }[] }
  const extResp = await graphFetch<ExtResp>(
    token,
    `/me/events/${ev.id}/extensions`
  );
  const ext = extResp.value?.find(
    (e) => e.extensionName === POLICY_EXTENSION_NAME
  );
  if (!ext?.payload) return null;

  try {
    const parsed = JSON.parse(ext.payload) as unknown;
    if (!parsed || typeof parsed !== "object") return null;
    const candidate = parsed as QvctPolicy;
    const v = validatePolicy(candidate);
    if (!v.ok) {
      console.warn("[policyStorage] payload invalide, fallback défaut", v.errors);
      return null;
    }
    return clonePolicy(candidate);
  } catch (err) {
    console.warn("[policyStorage] parse payload échoué", err);
    return null;
  }
}

/** Upsert de la politique. Crée l'event sentinelle si absent. */
export async function writePolicyToGraph(
  token: string,
  policy: QvctPolicy
): Promise<void> {
  const v = validatePolicy(policy);
  if (!v.ok) {
    throw new Error(
      "Politique invalide — " + Object.values(v.errors).join(" / ")
    );
  }

  const calendarId = await findOrCreateGr33tRecoveryCalendar(token);
  const existing = await findPolicyEvent(token, calendarId);
  const payload = JSON.stringify(policy);

  if (!existing) {
    // POST event + extension
    await graphFetch(token, `/me/calendars/${calendarId}/events`, {
      method: "POST",
      body: JSON.stringify({
        subject: POLICY_EVENT_SUBJECT,
        body: {
          contentType: "text",
          content: "Politique QVCT Gr33t (ne pas supprimer).",
        },
        start: { dateTime: `${POLICY_SENTINEL_START}T00:00:00`, timeZone: "UTC" },
        end: { dateTime: `${POLICY_SENTINEL_END}T00:00:00`, timeZone: "UTC" },
        isAllDay: true,
        showAs: "free",
        isReminderOn: false,
        extensions: [
          {
            "@odata.type": "microsoft.graph.openTypeExtension",
            extensionName: POLICY_EXTENSION_NAME,
            schemaVersion: 1,
            payload,
          },
        ],
      }),
    });
    return;
  }

  // Event existe déjà : PATCH l'extension (upsert)
  await graphFetch(
    token,
    `/me/events/${existing.id}/extensions/${POLICY_EXTENSION_NAME}`,
    {
      method: "PATCH",
      body: JSON.stringify({
        "@odata.type": "microsoft.graph.openTypeExtension",
        extensionName: POLICY_EXTENSION_NAME,
        schemaVersion: 1,
        payload,
      }),
    }
  ).catch(async (err) => {
    // Extension absente → POST au lieu de PATCH
    if (/404/.test(String(err))) {
      await graphFetch(token, `/me/events/${existing.id}/extensions`, {
        method: "POST",
        body: JSON.stringify({
          "@odata.type": "microsoft.graph.openTypeExtension",
          extensionName: POLICY_EXTENSION_NAME,
          schemaVersion: 1,
          payload,
        }),
      });
      return;
    }
    throw err;
  });
}

/** Constante DEFAULT_POLICY réexportée pour les call-sites qui veulent le fallback. */
export { DEFAULT_POLICY };
