/**
 * Génération du rendu HTML des events de score Gr33t Recovery (v1.1 IRA).
 *
 * Contraintes Outlook :
 *   - Styles inline uniquement (pas de <style>, pas de CSS externe)
 *   - Tables pour layout (compat Outlook Desktop Win32)
 *   - Polices système (pas de @font-face — on liste DM Sans en fallback)
 *
 * Tokens couleurs Gr33t :
 *   primary      #2266dd
 *   positive     #4dad33
 *   intermediate #ed6d2d
 *   negative     #ef4e78
 */
export type { DailyScores } from "../dashboard/rythme/scoring/daily";

/**
 * Sous-ensemble minimal requis pour le rendu — compatible avec `DailyScores`.
 * Découpler le body du type complet permet de le tester sans importer
 * l'ensemble du moteur de scoring.
 */
export interface DailyScoresLite {
  transitions: number;
  concentration: number;
  horaires: number;
  focus: number;
  ira: number;
}

const COLOR_PRIMARY = "#2266dd";
const COLOR_POSITIVE = "#4dad33";
const COLOR_INTERMEDIATE = "#ed6d2d";
const COLOR_NEGATIVE = "#ef4e78";
const COLOR_SURFACE_VARIANT = "#e3e8f0";
const COLOR_ON_SURFACE = "#1a1c1e";
const COLOR_ON_SURFACE_MUTED = "rgba(26, 28, 30, 0.6)";

/** Libellé qualitatif de l'IRA (aligné sur iraLabel du dashboard). */
export function iraBand(ira: number): { label: string; color: string } {
  if (ira >= 70) return { label: "Excellente capacité", color: COLOR_POSITIVE };
  if (ira >= 50) return { label: "Capacité modérée", color: COLOR_INTERMEDIATE };
  return { label: "Capacité faible", color: COLOR_NEGATIVE };
}

/** Couleur d'une barre de facteur selon son score 0-100. */
function factorBarColor(value: number): string {
  if (value >= 70) return COLOR_POSITIVE;
  if (value >= 50) return COLOR_INTERMEDIATE;
  return COLOR_NEGATIVE;
}

const FACTOR_LABELS = {
  transitions: "Transitions préservées",
  concentration: "Plages de concentration",
  horaires: "Respect des horaires",
  focus: "Focus en réunion",
} as const;

/**
 * Compte le nombre de facteurs "OK" (score ≥ 70), utilisé pour le subject.
 */
export function countFactorsOk(s: DailyScoresLite): number {
  let n = 0;
  if (s.transitions >= 70) n++;
  if (s.concentration >= 70) n++;
  if (s.horaires >= 70) n++;
  if (s.focus >= 70) n++;
  return n;
}

/**
 * Subject de l'event calendrier.
 *
 * Exemples :
 *   "IRA 78 · 3 facteurs OK"
 *   "IRA 42 · aucun facteur OK"
 */
export function buildEventSubject(scores: DailyScoresLite): string {
  const n = countFactorsOk(scores);
  const suffix =
    n === 0
      ? "aucun facteur OK"
      : `${n} facteur${n > 1 ? "s" : ""} OK`;
  return `IRA ${scores.ira} · ${suffix}`;
}

function bar(value: number): string {
  const width = Math.max(0, Math.min(100, value));
  const color = factorBarColor(value);
  return `
    <div style="background:${COLOR_SURFACE_VARIANT};border-radius:4px;height:6px;overflow:hidden;width:140px;">
      <div style="background:${color};height:100%;width:${width}%;"></div>
    </div>
  `;
}

function factorRow(label: string, value: number): string {
  return `
    <tr>
      <td style="padding:6px 0;font-size:13px;color:${COLOR_ON_SURFACE};">${label}</td>
      <td style="padding:6px 12px;font-size:13px;font-weight:700;color:${COLOR_ON_SURFACE};text-align:right;width:40px;">${value}</td>
      <td style="padding:6px 0;width:140px;">${bar(value)}</td>
    </tr>
  `;
}

/**
 * Produit le HTML complet du body de l'event.
 */
export function buildEventBody(scores: DailyScoresLite): string {
  const band = iraBand(scores.ira);
  return `
<div style="font-family:'DM Sans','Segoe UI',sans-serif;color:${COLOR_ON_SURFACE};max-width:520px;">
  <div style="font-size:11px;font-weight:700;color:${COLOR_ON_SURFACE_MUTED};text-transform:uppercase;letter-spacing:0.8px;margin-bottom:8px;">
    Indice de Récupération Active
  </div>
  <div style="display:flex;align-items:baseline;gap:16px;margin-bottom:20px;">
    <span style="font-size:48px;font-weight:800;color:${band.color};line-height:1;">${scores.ira}</span>
    <span style="font-size:14px;font-weight:600;color:${band.color};">${band.label}</span>
  </div>
  <hr style="border:none;border-top:1px solid ${COLOR_SURFACE_VARIANT};margin:12px 0;" />
  <table cellspacing="0" cellpadding="0" style="width:100%;border-collapse:collapse;">
    <tbody>
      ${factorRow(FACTOR_LABELS.transitions, scores.transitions)}
      ${factorRow(FACTOR_LABELS.concentration, scores.concentration)}
      ${factorRow(FACTOR_LABELS.horaires, scores.horaires)}
      ${factorRow(FACTOR_LABELS.focus, scores.focus)}
    </tbody>
  </table>
  <hr style="border:none;border-top:1px solid ${COLOR_SURFACE_VARIANT};margin:16px 0 12px;" />
  <div style="font-size:12px;color:${COLOR_ON_SURFACE_MUTED};">
    Détail et historique sur le
    <a href="https://app.gr33t.fr/dashboard.html" style="color:${COLOR_PRIMARY};text-decoration:none;font-weight:600;">
      dashboard Gr33t
    </a>.
  </div>
</div>
`.trim();
}
